x_snc_airop_check_definition.check_script:
(function(){
var ga=new GlideAggregate("sn_vdr_risk_asmt_issue_generation_rule");
ga.addAggregate("COUNT");ga.query();
var c=ga.next()?parseInt(ga.getAggregate("COUNT")):0;
if(c>=3)return{status:"ready",actualValue:c+" rules",finding:c+" issue generation rules configured."};
if(c>0)return{status:"needs_attention",actualValue:c+" rules",finding:c+" rule(s) found."};
return{status:"value_blocker",actualValue:"0 rules",finding:"No issue generation rules configured."};
})()
